type TxFormData struct {
	Editing           bool
	ID                int64
	Date              string // YYYY-MM-DD
	AccountID         int64
	CategoryID        *int64
	TransferAccountID *int64
	Payee             string
	Notes             string
	Outflow           string
	Inflow            string
	Accounts          []store.AccountWithBalance
	Categories        []store.Category
}

func accountFilterOptions(accts []store.AccountWithBalance, selected *int64) []selectbox.Option {
	out := make([]selectbox.Option, 0, len(accts)+1)
	out = append(out, selectbox.Option{Value: "", Label: "All accounts", Selected: selected == nil})
	for _, a := range accts {
		out = append(out, selectbox.Option{
			Value:    strconv.FormatInt(a.ID, 10),
			Label:    a.Name,
			Selected: selected != nil && *selected == a.ID,
		})
	}
	return out
}

func accountOptions(accts []store.AccountWithBalance, selectedID int64) []selectbox.Option {
	out := make([]selectbox.Option, 0, len(accts))
	for _, a := range accts {
		out = append(out, selectbox.Option{
			Value:    strconv.FormatInt(a.ID, 10),
			Label:    a.Name,
			Selected: a.ID == selectedID,
		})
	}
	return out
}

func categoryOptions(cats []store.Category, selected *int64) []selectbox.Option {
	out := make([]selectbox.Option, 0, len(cats))
	for _, c := range cats {
		out = append(out, selectbox.Option{
			Value:    strconv.FormatInt(c.ID, 10),
			Label:    c.Name,
			Selected: selected != nil && *selected == c.ID,
		})
	}
	return out
}

func transferOptions(accts []store.AccountWithBalance, selected *int64) []selectbox.Option {
	out := make([]selectbox.Option, 0, len(accts))
	for _, a := range accts {
		out = append(out, selectbox.Option{
			Value:    strconv.FormatInt(a.ID, 10),
			Label:    a.Name,
			Selected: selected != nil && *selected == a.ID,
		})
	}
	return out
}

func accountName(accts []store.AccountWithBalance, id int64) string {
	for _, a := range accts {
		if a.ID == id {
			return a.Name
		}
	}
	return ""
}

func categoryName(cats []store.Category, id int64) string {
	for _, c := range cats {
		if c.ID == id {
			return c.Name
		}
	}
	return ""
}

func transactionsPageHref(d TransactionsData, page int) string {
	q := fmt.Sprintf("/transactions?page=%d", page)
	if d.FilterMonth != "" {
		q += "&month=" + d.FilterMonth
	} else {
		q += "&all=1"
	}
	if d.FilterAccount != nil {
		q += fmt.Sprintf("&account=%d", *d.FilterAccount)
	}
	return q
}

// txMonthHref builds a /transactions URL pointing at the given month
// (or "all months" when month is empty), preserving the active account
// filter.
func txMonthHref(d TransactionsData, month string) string {
	q := "/transactions"
	if month != "" {
		q += "?month=" + month
	} else {
		q += "?all=1"
	}
	if d.FilterAccount != nil {
		q += fmt.Sprintf("&account=%d", *d.FilterAccount)
	}
	return q
}

func sameDay(a, b time.Time) bool {
	ay, am, ad := a.Date()
	by, bm, bd := b.Date()
	return ay == by && am == bm && ad == bd
}

func txMonthLabel(month string) string {
	if month == "" {
		return "All months"
	}
	t, err := time.Parse("2006-01", month)
	if err != nil {
		return month
	}
	return t.Format("January 2006")
}

